1508: /*
1509:  * Curl_cookie_freelist
1510:  *
1511:  * Free a list of cookies previously returned by Curl_cookie_getlist();
1512:  */
1513: void Curl_cookie_freelist(struct Cookie *co)
1514: {
1515:   struct Cookie *next;
1516:   while(co) {
1517:     next = co->next;
1518:     freecookie(co);
1519:     co = next;
1520:   }
1521: }
