1629:   if(!c)
1630:     /* no cookie engine alive */
1631:     return CURLE_OK;
1632: 
1633:   /* at first, remove expired cookies */
1634:   remove_expired(c);
1635: 
1636:   if(!strcmp("-", filename)) {
1637:     /* use stdout */
1638:     out = stdout;
1639:     use_stdout = TRUE;
1640:   }
1641:   else {
1642:     error = Curl_fopen(data, filename, &out, &tempstore);
1643:     if(error)
1644:       goto error;
1645:   }
1646: 
1647:   fputs("# Netscape HTTP Cookie File\n"
1648:         "# https://curl.se/docs/http-cookies.html\n"
1649:         "# This file was generated by libcurl! Edit at your own risk.\n\n",
1650:         out);
1651: 
1652:   if(c->numcookies) {
1653:     unsigned int i;
1654:     size_t nvalid = 0;
1655:     struct Cookie **array;
1656: 
1657:     array = calloc(1, sizeof(struct Cookie *) * c->numcookies);
1658:     if(!array) {
1659:       error = CURLE_OUT_OF_MEMORY;
1660:       goto error;
1661:     }
1662: 
1663:     /* only sort the cookies with a domain property */
1664:     for(i = 0; i < COOKIE_HASH_SIZE; i++) {
1665:       for(co = c->cookies[i]; co; co = co->next) {
1666:         if(!co->domain)
1667:           continue;
1668:         array[nvalid++] = co;
1669:       }
1670:     }
1671: 
1672:     qsort(array, nvalid, sizeof(struct Cookie *), cookie_sort_ct);
1673: 
1674:     for(i = 0; i < nvalid; i++) {
1675:       char *format_ptr = get_netscape_format(array[i]);
1676:       if(!format_ptr) {
1677:         free(array);
1678:         error = CURLE_OUT_OF_MEMORY;
1679:         goto error;
1680:       }
1681:       fprintf(out, "%s\n", format_ptr);
1682:       free(format_ptr);
1683:     }
1684: 
1685:     free(array);
1686:   }
1687: 
1688:   if(!use_stdout) {
1689:     fclose(out);
1690:     out = NULL;
